            builder.Append('|');
            builder.Append("PrtPrice=");
            builder.Append(this.PrtPrice);
            builder.Append('|');
            builder.Append("SrcTimestamp=");
            builder.Append(this.SrcTimestamp);
            builder.Append('|');
            builder.Append("NetTimestamp=");
            builder.Append(this.NetTimestamp);
            builder.Append('|');
            builder.Append("Timestamp=");
            builder.Append(this.Timestamp);
            builder.Append('|');
            builder.Append("Underlying=");
            builder.Append("'");
            for (int i = 0; i < UnderlyingLength && this.GetUnderlying(i) > 0; ++i)
            {
                builder.Append((char)this.GetUnderlying(i));
            }
            builder.Append("'");
            builder.Append('|');
            builder.Append("Symbol=");
            builder.Append('\'').Append(GetSymbol()).Append('\'');
            builder.Append('|');
            builder.Append("SpreadId=");
            builder.Append('\'').Append(GetSpreadId()).Append('\'');
            builder.Append('|');
            builder.Append("SpreadDescription=");
            builder.Append('\'').Append(GetSpreadDescription()).Append('\'');

            this.Limit = originalLimit;

        }
    }
}
